@using sv_7cb8dd54ab5d4025b0d4faed84461fb4.Models

<div class="step-indicator">
    @for (int i = 0; i < StepNames.Length; i++)
    {
        var step = i;
        var css = step == CurrentStep ? "step active"
                : CompletedSteps.Contains(step) ? "step completed"
                : "step";

        <div class="@css" @onclick="() => OnStepClick(step)">
            <div class="step-circle">
                @if (CompletedSteps.Contains(step) && step != CurrentStep)
                {
                    <span>✓</span>
                }
                else
                {
                    <span>@(step + 1)</span>
                }
            </div>
            <div class="step-label">@StepNames[step]</div>
        </div>

        @if (i < StepNames.Length - 1)
        {
            <div class="step-connector @(CompletedSteps.Contains(step) ? "completed" : "")"></div>
        }
    }
</div>

@code {
    private static readonly string[] StepNames =
        ["Personal Info", "Work History", "References", "Cover Letter", "Review & Submit"];

    [Parameter, EditorRequired] public int CurrentStep { get; set; }
    [Parameter, EditorRequired] public HashSet<int> CompletedSteps { get; set; } = new();
    [Parameter] public EventCallback<int> OnStepClicked { get; set; }

    private async Task OnStepClick(int step)
    {
        if (CompletedSteps.Contains(step))
        {
            await OnStepClicked.InvokeAsync(step);
        }
    }
}

.step-indicator {
    display: flex;
    align-items: center;
    justify-content: center;
    margin-bottom: 2rem;
    padding: 1rem 0;
}

.step {
    display: flex;
    flex-direction: column;
    align-items: center;
    cursor: default;
    opacity: 0.4;
    transition: opacity 0.2s;
}

.step.active {
    opacity: 1;
}

.step.completed {
    opacity: 0.85;
    cursor: pointer;
}

.step-circle {
    width: 36px;
    height: 36px;
    border-radius: 50%;
    background: #dee2e6;
    display: flex;
    align-items: center;
    justify-content: center;
    font-weight: 600;
    font-size: 0.9rem;
    color: #495057;
    transition: background 0.2s, color 0.2s;
}

.step.active .step-circle {
    background: #0d6efd;
    color: #fff;
}

.step.completed .step-circle {
    background: #198754;
    color: #fff;
}

.step-label {
    margin-top: 0.4rem;
    font-size: 0.75rem;
    font-weight: 500;
    white-space: nowrap;
}

.step-connector {
    flex: 1;
    height: 2px;
    background: #dee2e6;
    margin: 0 0.5rem;
    margin-bottom: 1.2rem;
    max-width: 80px;
    transition: background 0.2s;
}

.step-connector.completed {
    background: #198754;
}

.work-entry-card {
    border: 1px solid #dee2e6;
    border-radius: 0.5rem;
    padding: 1.25rem;
    margin-bottom: 1rem;
    background: #f8f9fa;
}

.entry-header {
    display: flex;
    justify-content: space-between;
    align-items: center;
    margin-bottom: 1rem;
}

.entry-header h5 {
    margin: 0;
}

@using sv_7cb8dd54ab5d4025b0d4faed84461fb4.Models

<div class="reference-card">
    <div class="entry-header">
        <h5>Reference @(Index + 1)</h5>
        @if (CanRemove)
        {
            <button type="button" class="btn btn-outline-danger btn-sm" @onclick="() => OnRemove.InvokeAsync()">Remove</button>
        }
    </div>

    <div class="row mb-3">
        <div class="col-md-6">
            <label class="form-label">Full Name <span class="text-danger">*</span></label>
            <input type="text" class="form-control" @bind="Ref.Name" @bind:event="oninput" />
        </div>
        <div class="col-md-6">
            <label class="form-label">Relationship <span class="text-danger">*</span></label>
            <input type="text" class="form-control" @bind="Ref.Relationship" @bind:event="oninput" />
        </div>
    </div>

    <div class="row mb-3">
        <div class="col-md-6">
            <label class="form-label">Email <span class="text-danger">*</span></label>
            <input type="email" class="form-control" @bind="Ref.Email" @bind:event="oninput" />
        </div>
        <div class="col-md-6">
            <label class="form-label">Phone <span class="text-danger">*</span></label>
            <input type="tel" class="form-control" @bind="Ref.Phone" @bind:event="oninput" />
        </div>
    </div>
</div>

@code {
    [Parameter, EditorRequired] public ReferenceModel Ref { get; set; } = default!;
    [Parameter] public int Index { get; set; }
    [Parameter] public bool CanRemove { get; set; }
    [Parameter] public EventCallback OnRemove { get; set; }
}

.reference-card {
    border: 1px solid #dee2e6;
    border-radius: 0.5rem;
    padding: 1.25rem;
    margin-bottom: 1rem;
    background: #f8f9fa;
}

.entry-header {
    display: flex;
    justify-content: space-between;
    align-items: center;
    margin-bottom: 1rem;
}

.entry-header h5 {
    margin: 0;
}

