arguments.file_text:
@using sv_7cb8dd54ab5d4025b0d4faed84461fb4.Models

<h4>Personal Information</h4>

@if (!string.IsNullOrEmpty(_error))
{
    <div class="alert alert-danger">@_error</div>
}

<div class="row mb-3">
    <div class="col-md-6">
        <label class="form-label">Full Name <span class="text-danger">*</span></label>
        <input type="text" class="form-control" @bind="Model.FullName" @bind:event="oninput" />
    </div>
    <div class="col-md-6">
        <label class="form-label">Email <span class="text-danger">*</span></label>
        <input type="email" class="form-control" @bind="Model.Email" @bind:event="oninput" />
    </div>
</div>

<div class="row mb-3">
    <div class="col-md-6">
        <label class="form-label">Phone <span class="text-danger">*</span></label>
        <input type="tel" class="form-control" @bind="Model.Phone" @bind:event="oninput" />
    </div>
    <div class="col-md-6">
        <label class="form-label">Address <span class="text-danger">*</span></label>
        <input type="text" class="form-control" @bind="Model.Address" @bind:event="oninput" />
    </div>
</div>

<div class="d-flex justify-content-end mt-4">
    <button class="btn btn-primary" @onclick="HandleNext" disabled="@_validating">
        @if (_validating)
        {
            <span class="spinner-border spinner-border-sm me-1"></span>
            <span>Validating…</span>
        }
        else
        {
            <span>Next →</span>
        }
    </button>
</div>

@code {
    [Parameter, EditorRequired] public PersonalInfoModel Model { get; set; } = default!;
    [Parameter] public EventCallback OnNext { get; set; }
    [Parameter] public Func<string, Task<bool>>? ValidateEmail { get; set; }

    private string? _error;
    private bool _validating;

    private async Task HandleNext()
    {
        _error = null;

        if (!Model.IsValid)
        {
            _error = "Please fill in all required fields.";
            return;
        }

        if (ValidateEmail is not null)
        {
            _validating = true;
            try
            {
                var valid = await ValidateEmail(Model.Email);
                if (!valid)
                {
                    _error = "Please enter a valid email address.";
                    return;
                }
            }
            finally
            {
                _validating = false;
            }
        }

        await OnNext.InvokeAsync();
    }
}

@using sv_7cb8dd54ab5d4025b0d4faed84461fb4.Models

<h4>Work History</h4>

@if (!string.IsNullOrEmpty(_error))
{
    <div class="alert alert-danger">@_error</div>
}

@for (int i = 0; i < Entries.Count; i++)
{
    var index = i;
    <WorkEntryForm Entry="Entries[index]"
                   Index="index"
                   CanRemove="Entries.Count > 1"
                   OnRemove="() => RemoveEntry(index)" />
}

<button type="button" class="btn btn-outline-secondary mb-3" @onclick="AddEntry">
    + Add Another Position
</button>

<div class="d-flex justify-content-between mt-4">
    <button class="btn btn-outline-secondary" @onclick="OnBack">← Back</button>
    <button class="btn btn-primary" @onclick="HandleNext">Next →</button>
</div>

@code {
    [Parameter, EditorRequired] public List<WorkEntryModel> Entries { get; set; } = default!;
    [Parameter] public EventCallback OnNext { get; set; }
    [Parameter] public EventCallback OnBack { get; set; }

    private string? _error;

    private void AddEntry() => Entries.Add(new WorkEntryModel());

    private void RemoveEntry(int index)
    {
        if (Entries.Count > 1)
            Entries.RemoveAt(index);
    }

    private async Task HandleNext()
    {
        _error = null;
        if (!Entries.All(e => e.IsValid))
        {
            _error = "Please fill in company, title, and start date for all positions.";
            return;
        }
        await OnNext.InvokeAsync();
    }
}

@using sv_7cb8dd54ab5d4025b0d4faed84461fb4.Models

<h4>References</h4>

@if (!string.IsNullOrEmpty(_error))
{
    <div class="alert alert-danger">@_error</div>
}

@for (int i = 0; i < References.Count; i++)
{
    var index = i;
    <ReferenceForm Ref="References[index]"
                   Index="index"
                   CanRemove="References.Count > 2"
                   OnRemove="() => RemoveReference(index)" />
}

@if (References.Count < 3)
{
    <button type="button" class="btn btn-outline-secondary mb-3" @onclick="AddReference">
        + Add Reference
    </button>
}

<div class="d-flex justify-content-between mt-4">
    <button class="btn btn-outline-secondary" @onclick="OnBack">← Back</button>
    <button class="btn btn-primary" @onclick="HandleNext">Next →</button>
</div>

@code {
    [Parameter, EditorRequired] public List<ReferenceModel> References { get; set; } = default!;
    [Parameter] public EventCallback OnNext { get; set; }
    [Parameter] public EventCallback OnBack { get; set; }

    private string? _error;

    private void AddReference()
    {
        if (References.Count < 3)
            References.Add(new ReferenceModel());
    }

    private void RemoveReference(int index)
    {
        if (References.Count > 2)
            References.RemoveAt(index);
    }

    private async Task HandleNext()
    {
        _error = null;
        if (!References.All(r => r.IsValid))
        {
            _error = "Please fill in all fields for each reference.";
            return;
        }
        await OnNext.InvokeAsync();
    }
}

@using sv_7cb8dd54ab5d4025b0d4faed84461fb4.Models

<h4>Cover Letter</h4>

<div class="mb-3">
    <label class="form-label">Write your cover letter</label>
    <textarea class="form-control" rows="12"
              @bind="CoverLetter"
              @bind:event="oninput"
              @bind:after="NotifyChanged"
              maxlength="@MaxLength"></textarea>
    <div class="form-text text-end">
        @CoverLetter.Length / @MaxLength characters
    </div>
</div>

@if (!string.IsNullOrEmpty(_error))
{
    <div class="alert alert-danger">@_error</div>
}

<div class="d-flex justify-content-between mt-4">
    <button class="btn btn-outline-secondary" @onclick="OnBack">← Back</button>
    <button class="btn btn-primary" @onclick="HandleNext">Next →</button>
</div>

@code {
    private const int MaxLength = 2000;

    [Parameter] public string CoverLetter { get; set; } = "";
    [Parameter] public EventCallback<string> CoverLetterChanged { get; set; }
    [Parameter] public EventCallback OnNext { get; set; }
    [Parameter] public EventCallback OnBack { get; set; }

    private string? _error;

    private async Task NotifyChanged() => await CoverLetterChanged.InvokeAsync(CoverLetter);

    private async Task HandleNext()
    {
        _error = null;
        if (string.IsNullOrWhiteSpace(CoverLetter))
        {
            _error = "Please write a cover letter.";
            return;
        }
        await OnNext.InvokeAsync();
    }
}

@using sv_7cb8dd54ab5d4025b0d4faed84461fb4.Models

<h4>Review & Submit</h4>

<div class="review-section">
    <div class="review-header">
        <h5>Personal Information</h5>
        <button class="btn btn-link btn-sm" @onclick='() => OnEditSection.InvokeAsync(0)'>Edit</button>
    </div>
    <dl class="row mb-0">
        <dt class="col-sm-3">Name</dt>
        <dd class="col-sm-9">@Personal.FullName</dd>
        <dt class="col-sm-3">Email</dt>
        <dd class="col-sm-9">@Personal.Email</dd>
        <dt class="col-sm-3">Phone</dt>
        <dd class="col-sm-9">@Personal.Phone</dd>
        <dt class="col-sm-3">Address</dt>
        <dd class="col-sm-9">@Personal.Address</dd>
    </dl>
</div>

<div class="review-section">
    <div class="review-header">
        <h5>Work History</h5>
        <button class="btn btn-link btn-sm" @onclick='() => OnEditSection.InvokeAsync(1)'>Edit</button>
    </div>
    @foreach (var entry in WorkEntries)
    {
        <div class="mb-2 ps-2 border-start border-3">
            <strong>@entry.Title</strong> at @entry.Company<br />
            <small class="text-muted">
                @entry.StartDate?.ToString("MMM yyyy") –
                @(entry.IsCurrent ? "Present" : entry.EndDate?.ToString("MMM yyyy"))
            </small>
            @if (!string.IsNullOrWhiteSpace(entry.Description))
            {
                <p class="mb-0 mt-1">@entry.Description</p>
            }
        </div>
    }
</div>

<div class="review-section">
    <div class="review-header">
        <h5>References</h5>
        <button class="btn btn-link btn-sm" @onclick='() => OnEditSection.InvokeAsync(2)'>Edit</button>
    </div>
    @foreach (var r in References)
    {
        <div class="mb-2 ps-2 border-start border-3">
            <strong>@r.Name</strong> — @r.Relationship<br />
            <small class="text-muted">@r.Email · @r.Phone</small>
        </div>
    }
</div>

<div class="review-section">
    <div class="review-header">
        <h5>Cover Letter</h5>
        <button class="btn btn-link btn-sm" @onclick='() => OnEditSection.InvokeAsync(3)'>Edit</button>
    </div>
    <p style="white-space: pre-wrap;">@CoverLetter</p>
</div>

@if (!string.IsNullOrEmpty(_error))
{
    <div class="alert alert-danger mt-3">@_error</div>
}

<div class="d-flex justify-content-between mt-4">
    <button class="btn btn-outline-secondary" @onclick="OnBack">← Back</button>
    <button class="btn btn-success btn-lg" @onclick="HandleSubmit" disabled="@_submitting">
        @if (_submitting)
        {
            <span class="spinner-border spinner-border-sm me-1"></span>
            <span>Submitting…</span>
        }
        else
        {
            <span>Submit Application</span>
        }
    </button>
</div>

@code {
    [Parameter, EditorRequired] public PersonalInfoModel Personal { get; set; } = default!;
    [Parameter, EditorRequired] public List<WorkEntryModel> WorkEntries { get; set; } = default!;
    [Parameter, EditorRequired] public List<ReferenceModel> References { get; set; } = default!;
    [Parameter, EditorRequired] public string CoverLetter { get; set; } = "";
    [Parameter] public EventCallback<int> OnEditSection { get; set; }
    [Parameter] public EventCallback OnBack { get; set; }
    [Parameter] public EventCallback OnSubmit { get; set; }

    private bool _submitting;
    private string? _error;

    private async Task HandleSubmit()
    {
        _error = null;
        _submitting = true;
        try
        {
            await OnSubmit.InvokeAsync();
        }
        catch (Exception ex)
        {
            _error = $"Submission failed: {ex.Message}";
        }
        finally
        {
            _submitting = false;
        }
    }
}

