toolArgs.file_text:
@using sv_7cb8dd54ab5d4025b0d4faed84461fb4.Models

<h4>Review & Submit</h4>

<div class="review-section">
    <div class="review-header">
        <h5>Personal Information</h5>
        <button class="btn btn-link btn-sm" @onclick='() => OnEditSection.InvokeAsync(0)'>Edit</button>
    </div>
    <dl class="row mb-0">
        <dt class="col-sm-3">Name</dt>
        <dd class="col-sm-9">@Personal.FullName</dd>
        <dt class="col-sm-3">Email</dt>
        <dd class="col-sm-9">@Personal.Email</dd>
        <dt class="col-sm-3">Phone</dt>
        <dd class="col-sm-9">@Personal.Phone</dd>
        <dt class="col-sm-3">Address</dt>
        <dd class="col-sm-9">@Personal.Address</dd>
    </dl>
</div>

<div class="review-section">
    <div class="review-header">
        <h5>Work History</h5>
        <button class="btn btn-link btn-sm" @onclick='() => OnEditSection.InvokeAsync(1)'>Edit</button>
    </div>
    @foreach (var entry in WorkEntries)
    {
        <div class="mb-2 ps-2 border-start border-3">
            <strong>@entry.Title</strong> at @entry.Company<br />
            <small class="text-muted">
                @entry.StartDate?.ToString("MMM yyyy") –
                @(entry.IsCurrent ? "Present" : entry.EndDate?.ToString("MMM yyyy"))
            </small>
            @if (!string.IsNullOrWhiteSpace(entry.Description))
            {
                <p class="mb-0 mt-1">@entry.Description</p>
            }
        </div>
    }
</div>

<div class="review-section">
    <div class="review-header">
        <h5>References</h5>
        <button class="btn btn-link btn-sm" @onclick='() => OnEditSection.InvokeAsync(2)'>Edit</button>
    </div>
    @foreach (var r in References)
    {
        <div class="mb-2 ps-2 border-start border-3">
            <strong>@r.Name</strong> — @r.Relationship<br />
            <small class="text-muted">@r.Email · @r.Phone</small>
        </div>
    }
</div>

<div class="review-section">
    <div class="review-header">
        <h5>Cover Letter</h5>
        <button class="btn btn-link btn-sm" @onclick='() => OnEditSection.InvokeAsync(3)'>Edit</button>
    </div>
    <p style="white-space: pre-wrap;">@CoverLetter</p>
</div>

@if (!string.IsNullOrEmpty(_error))
{
    <div class="alert alert-danger mt-3">@_error</div>
}

<div class="d-flex justify-content-between mt-4">
    <button class="btn btn-outline-secondary" @onclick="OnBack">← Back</button>
    <button class="btn btn-success btn-lg" @onclick="HandleSubmit" disabled="@_submitting">
        @if (_submitting)
        {
            <span class="spinner-border spinner-border-sm me-1"></span>
            <span>Submitting…</span>
        }
        else
        {
            <span>Submit Application</span>
        }
    </button>
</div>

@code {
    [Parameter, EditorRequired] public PersonalInfoModel Personal { get; set; } = default!;
    [Parameter, EditorRequired] public List<WorkEntryModel> WorkEntries { get; set; } = default!;
    [Parameter, EditorRequired] public List<ReferenceModel> References { get; set; } = default!;
    [Parameter, EditorRequired] public string CoverLetter { get; set; } = "";
    [Parameter] public EventCallback<int> OnEditSection { get; set; }
    [Parameter] public EventCallback OnBack { get; set; }
    [Parameter] public EventCallback OnSubmit { get; set; }

    private bool _submitting;
    private string? _error;

    private async Task HandleSubmit()
    {
        _error = null;
        _submitting = true;
        try
        {
            await OnSubmit.InvokeAsync();
        }
        catch (Exception ex)
        {
            _error = $"Submission failed: {ex.Message}";
        }
        finally
        {
            _submitting = false;
        }
    }
}

.review-section {
    border: 1px solid #dee2e6;
    border-radius: 0.5rem;
    padding: 1rem 1.25rem;
    margin-bottom: 1rem;
    background: #f8f9fa;
}

.review-header {
    display: flex;
    justify-content: space-between;
    align-items: center;
    margin-bottom: 0.75rem;
}

.review-header h5 {
    margin: 0;
}

