<PageTitle>Job Application</PageTitle>

<div class="container py-4" style="max-width: 800px;">
    <h2 class="text-center mb-4">Job Application</h2>

    @if (_submitted)
    {
        <div class="text-center py-5">
            <div class="mb-3" style="font-size: 3rem;">✅</div>
            <h3>Application Submitted!</h3>
            <p class="lead">Your application ID is <strong>#@_applicationId</strong></p>
            <p class="text-muted">We'll review your application and get back to you soon.</p>
        </div>
    }
    else
    {
        <StepIndicator CurrentStep="_currentStep"
                       CompletedSteps="_completedSteps"
                       OnStepClicked="GoToStep" />

        @switch (_currentStep)
        {
            case 0:
                <PersonalInfoStep Model="_personal"
                                  ValidateEmail="AppService.ValidateEmailAsync"
                                  OnNext="() => CompleteAndAdvance(0)" />
                break;

            case 1:
                <WorkHistoryStep Entries="_workEntries"
                                 OnNext="() => CompleteAndAdvance(1)"
                                 OnBack="() => GoToStep(0)" />
                break;

            case 2:
                <ReferencesStep References="_references"
                                OnNext="() => CompleteAndAdvance(2)"
                                OnBack="() => GoToStep(1)" />
                break;

            case 3:
                <CoverLetterStep @bind-CoverLetter="_coverLetter"
                                 OnNext="() => CompleteAndAdvance(3)"
                                 OnBack="() => GoToStep(2)" />
                break;

            case 4:
                <ReviewStep Personal="_personal"
                            WorkEntries="_workEntries"
                            References="_references"
                            CoverLetter="_coverLetter"
                            OnEditSection="GoToStep"
                            OnBack="() => GoToStep(3)"
                            OnSubmit="SubmitApplication" />
                break;
        }
    }
</div>

@code {
    private int _currentStep;
    private readonly HashSet<int> _completedSteps = new();
    private bool _submitted;
    private int _applicationId;

    // Form state — owned by the page, passed down to steps
    private readonly PersonalInfoModel _personal = new();
    private readonly List<WorkEntryModel> _workEntries = [new()];
    private readonly List<ReferenceModel> _references = [new(), new()];
    private string _coverLetter = "";

    private void GoToStep(int step)
    {
        _currentStep = step;
    }

    private void CompleteAndAdvance(int step)
    {
        _completedSteps.Add(step);
        _currentStep = step + 1;
    }

    private async Task SubmitApplication()
    {
        var application = new JobApplication(
            _personal.ToRecord(),
            new WorkHistory(_workEntries.Select(e => e.ToRecord()).ToList()),
            _references.Select(r => r.ToRecord()).ToList(),
            _coverLetter);

        _applicationId = await AppService.SubmitApplicationAsync(application);
        _submitted = true;
    }
}

